const fs=require('fs');
const p='_worker.js';
let s=fs.readFileSync(p,'utf8');
const before=s;
s=s.replace('js=\\`<script type="module" id="customer-tracking-script">','js=`<script type="module" id="customer-tracking-script">');
s=s.replace('</script>\\`;return h.replace(\'</head>\',css+\'</head>\')','</script>`;return h.replace(\'</head>\',css+\'</head>\')');
if(s===before)throw new Error('escaped template markers not found');
fs.writeFileSync(p,s);
fs.rmSync('.github/fix-worker-template.cjs');
fs.rmSync('.github/workflows/fix-worker-template.yml');
